#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, Y; char s[35];
        scanf("%lld %lld", &X, &Y);
        scanf("%s", s);
        long long total=0, cur=0, best=0;
        for(int i=0; s[i]; ++i){
            if(s[i]=='1'){
                total++; cur++; if(cur>best) best=cur;
            }else cur=0;
        }
        printf("%lld", total*X + best*Y);
        if(T) printf("\n");
    }
    return 0;
}

